func generateWorkstationsWorkstationIAMPolicyStateID(iamResourceAddr string) func(*terraform.State) (string, error) {
	return func(state *terraform.State) (string, error) {
		var rawState map[string]string
		for _, m := range state.Modules {
			if len(m.Resources) > 0 {
				if v, ok := m.Resources[iamResourceAddr]; ok {
					rawState = v.Primary.Attributes
				}
			}
		}
		fmt.Printf("raw state %s\n", rawState)
		project := tpgresource.GetResourceNameFromSelfLink(rawState["project"])
		location := tpgresource.GetResourceNameFromSelfLink(rawState["location"])
		workstation_cluster_id := tpgresource.GetResourceNameFromSelfLink(rawState["workstation_cluster_id"])
		workstation_config_id := tpgresource.GetResourceNameFromSelfLink(rawState["workstation_config_id"])
		workstation_id := tpgresource.GetResourceNameFromSelfLink(rawState["workstation_id"])
		return acctest.BuildIAMImportId(fmt.Sprintf("projects/%s/locations/%s/workstationClusters/%s/workstationConfigs/%s/workstations/%s", project, location, workstation_cluster_id, workstation_config_id, workstation_id), "", "", rawState["condition.0.title"]), nil
	}
}

